import sys

class Graph:
    def __init__(self, numVertices):
        self.numVertices = numVertices
        self.adjList = [[] for _ in range(numVertices)]

    def addEdge(self, src, dest):
        self.adjList[src].append(dest)
        self.adjList[dest].append(src)

    def DFS(self, vertex, visited):
        visited[vertex] = True
        for i in self.adjList[vertex]:
            if not visited[i]:
                self.DFS(i, visited)

    def isPossible(self):
        visited = [False] * self.numVertices
        count = 0
        for i in range(self.numVertices):
            if not visited[i]:
                self.DFS(i, visited)
                count += 1
        return count

def main():
    T = int(input())
    for _ in range(T):
        N, M = map(int, input().split())
        graph = Graph(N)
        for _ in range(M):
            src, dest = map(int, input().split())
            graph.addEdge(src - 1, dest - 1)
        count = graph.isPossible()
        if count == N:
            print("YES")
        else:
            flag = 0
            for i in range(N):
                visited = [False] * N
                graph.DFS(i, visited)
                for j in range(N):
                    if visited[j] and j != i:
                        flag = 1
                        break
                if flag: break
            if flag: print("NO")
            else: print("YES")

if __name__ == '__main__':
